Here's the full setup:

**XAML — wrap `CollectionView` in a `RefreshView`:**

```xml
<RefreshView IsRefreshing="{Binding IsRefreshing}"
             Command="{Binding RefreshCommand}">
    <CollectionView ItemsSource="{Binding Items}"
                    SelectionMode="Single"
                    SelectedItem="{Binding CurrentItem, Mode=TwoWay}"
                    SelectionChangedCommand="{Binding ItemSelectedCommand}">
        <CollectionView.ItemTemplate>
            <DataTemplate x:DataType="models:Item">
                <Grid Padding="12" ColumnDefinitions="48,*">
                    <Image Source="{Binding Icon}"
                           WidthRequest="40" HeightRequest="40" />
                    <Label Grid.Column="1"
                           Text="{Binding Name}"
                           VerticalOptions="Center" />
                </Grid>
            </DataTemplate>
        </CollectionView.ItemTemplate>
        <CollectionView.EmptyView>
            <Label Text="No items found."
                   HorizontalOptions="Center"
                   VerticalOptions="Center" />
        </CollectionView.EmptyView>
    </CollectionView>
</RefreshView>
```

**ViewModel (using CommunityToolkit.Mvvm):**

```csharp
public partial class ItemsViewModel : ObservableObject
{
    private readonly IItemService _itemService;
    private readonly INavigationService _nav;

    [ObservableProperty]
    private Item? _currentItem;

    [ObservableProperty]
    private bool _isRefreshing;

    public ObservableCollection<Item> Items { get; } = new();

    public ItemsViewModel(IItemService itemService, INavigationService nav)
    {
        _itemService = itemService;
        _nav = nav;
    }

    [RelayCommand]
    private async Task ItemSelected()
    {
        if (CurrentItem is null) return;

        await _nav.GoToAsync($"detail?id={CurrentItem.Id}");

        // Reset so the same item can be re-selected later
        CurrentItem = null;
    }

    [RelayCommand]
    private async Task Refresh()
    {
        try
        {
            var data = await _itemService.GetItemsAsync();
            MainThread.BeginInvokeOnMainThread(() =>
            {
                Items.Clear();
                foreach (var item in data)
                    Items.Add(item);
            });
        }
        finally
        {
            IsRefreshing = false; // Stops the spinner
        }
    }
}
```

**Key bindings explained:**

| Property | Binding | Purpose |
|---|---|---|
| `ItemsSource` | `ObservableCollection<Item>` | Auto-updates UI on add/remove |
| `SelectedItem` | `CurrentItem` (TwoWay) | Tracks the selected item |
| `SelectionChangedCommand` | `ItemSelectedCommand` | Fires navigation on tap |
| `IsRefreshing` | `IsRefreshing` (TwoWay) | Controls the refresh spinner |
| `Command` (RefreshView) | `RefreshCommand` | Triggers API reload on pull |

**Important details:**
- Set `CurrentItem = null` after navigating so the same item can be re-selected.
- Set `IsRefreshing = false` in `finally` to always dismiss the spinner.
- Use `ObservableCollection<T>`, never `List<T>` — swapping a `List` forces a full re-render.
- Always update the collection on the **UI thread** via `MainThread.BeginInvokeOnMainThread`.
- Set `x:DataType` on `DataTemplate` for compiled bindings.
